#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 5e2 + 5, fy[] = {0, 0, -1, 1}, fx[] = {1, -1, 0, 0};
set <vector <int> > st;
vector <int> s;
int mp[MAXN][MAXN], n, m, sx, sy;
void dfs(int col, int x, int y)
{
	mp[x][y] = 0;
	s.push_back((sx - x) * 500 + (sy - y));
	for (int i = 0; i < 4; i++)
	{
		int nx = x + fx[i];
		int ny = y + fy[i];
		if (mp[nx][ny] == col) dfs(col, nx, ny);
	}
}
int main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= n; ++i)
		for (int j = 1; j <= m; ++j)
			cin >> mp[i][j];
	for (int i = 1; i <= n; ++i)
		for (int j = 1; j <= m; ++j)
			if (mp[i][j])
			{
				while (s.size()) s.pop_back();
				sx = i, sy = j;
				dfs(mp[i][j], i, j);
				st.insert(s);
			}
	cout << st.size();
	return false;
}
